// Parse XML file paths and prepare for processing
const xmlFiles = $input.all().map(item => {
  const filePath = item.json.stdout.trim();
  if (filePath) {
    return {
      json: {
        filePath: filePath,
        fileName: filePath.split('/').pop(),
        processed: false
      }
    };
  }
}).filter(item => item);

return xmlFiles;

// Parse XML news content
const xml2js = require('xml2js');
const parser = new xml2js.Parser();

const results = [];

for (const item of $input.all()) {
  try {
    const xmlContent = item.json.stdout;
    const parsed = await parser.parseStringPromise(xmlContent);

    // Extract news items (adjust based on your XML structure)
    const newsItems = parsed.news?.item || parsed.rss?.channel?.[0]?.item || [];

    for (const newsItem of newsItems) {
      results.push({
        json: {
          title: newsItem.title?.[0] || '',
          description: newsItem.description?.[0] || newsItem.summary?.[0] || '',
          pubDate: newsItem.pubDate?.[0] || newsItem.published?.[0] || '',
          category: newsItem.category?.[0] || '',
          filePath: $json.filePath,
          media: newsItem.enclosure || newsItem.media?.content || []
        }
      });
    }
  } catch (error) {
    console.error('Error parsing XML:', error);
  }
}

return results;

// Combine news data with supporting media
const results = [];

for (let i = 0; i < $input.all().length; i++) {
  const newsItem = $input.all()[i].json;
  const mediaSearch = $('Find Supporting Media').all()[i].json.stdout;

  const mediaFiles = mediaSearch.trim().split('\n').filter(file => file.trim());

  // Select anchor image (first image file)
  const anchorImage = mediaFiles.find(file => file.match(/\.(jpg|jpeg|png|gif)$/i)) || '';

  results.push({
    json: {
      ...newsItem,
      supportingMedia: mediaFiles,
      anchorImage: anchorImage,
      hasMedia: mediaFiles.length > 0
    }
  });
}

return results;

// Parse Ollama response and prepare for audio generation
const results = [];

for (const item of $input.all()) {
  try {
    const response = JSON.parse(item.json.body);
    const script = response.response || '';

    // Clean up the script
    const cleanScript = script.replace(/\[.*?\]/g, '').trim();

    results.push({
      json: {
        ...$('Combine News with Media').all()[0].json,
        aiScript: script,
        cleanScript: cleanScript,
        scriptLength: cleanScript.length
      }
    });
  } catch (error) {
    console.error('Error parsing Ollama response:', error);
  }
}

return results;

// Prepare final assembly data
const results = [];

for (const item of $input.all()) {
  const newsData = $('Parse Script Response').all()[0].json;
  const audioPath = `/home/engine/project/generated_assets/${newsData.title.replace(/[^a-zA-Z0-9]/g, '_').substring(0, 20)}/audio.mp3`;
  const videoPath = `/home/engine/project/generated_assets/${newsData.title.replace(/[^a-zA-Z0-9]/g, '_').substring(0, 20)}/video.mp4`;

  results.push({
    json: {
      ...newsData,
      audioPath: audioPath,
      videoPath: videoPath,
      outputPath: `/home/engine/project/final_bulletins/${newsData.title.replace(/[^a-zA-Z0-9]/g, '_').substring(0, 20)}_bulletin.mp4`
    }
  });
}

return results;

// Final cleanup and notification
const results = [];

for (const item of $input.all()) {
  const bulletinData = $('Prepare Assembly Data').all()[0].json;

  results.push({
    json: {
      status: 'completed',
      title: bulletinData.title,
      outputPath: bulletinData.outputPath,
      timestamp: new Date().toISOString(),
      duration: bulletinData.scriptLength
    }
  });
}

return results;

